import { GraphState } from "../../src/app/api/agent/route";

/**
 * Sends the post generated by the agent to Facebook via our internal API route.
 * Assumes the agent has already handled platform rules, formatting, and content.
 */
export async function facebookPosting(
  state: GraphState
): Promise<Partial<GraphState>> {
  const { post, platform, threadId } = state;

  if (!post) {
    throw new Error("Missing 'post' in state");
  }

  console.log("📡 Sending post to Facebook endpoint:", {
    post,
    platform,
    threadId,
  });

  const res = await fetch(
    `${process.env.NEXT_PUBLIC_BASE_URL}/api/postings/fb-posting`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ post, platform: "facebook" }),
    }
  );

  if (!res.ok) {
    let bodyText: string;

    try {
      const errorData = await res.json();
      console.error(" Facebook API failed with JSON:", errorData);
      bodyText = JSON.stringify(errorData, null, 2);
    } catch {
      bodyText = await res.text();
      console.error(" Facebook API failed with raw response:", bodyText);
    }

    throw new Error(
      `Facebook API error (status: ${res.status})\nResponse: ${bodyText}`
    );
  }

  const data = await res.json();

  console.log(" Facebook API success response:", data);

  return {
    ...state,
    post,
    threadId,
    result: data,
  };
}
